// COMPLETE, COMPILABLE C code
#include <stdio.h>
#include <stdlib.h>
#define MOD 1000000007
#define MAXN 100
#define MAXM 100
#define MAXK 10
#define MAXT 1000000000

int abs(int x) { return x < 0 ? -x : x; }

int main() {
    int N, M, R1, R2, K, t;
    scanf("%d %d %d %d %d %d", &N, &M, &R1, &R2, &K, &t);
    int minions[MAXK][4];
    for (int i = 0; i < K; i++) {
        scanf("%d %d %d %d", &minions[i][0], &minions[i][1], &minions[i][2], &minions[i][3]);
    }
    int dp[MAXN][MAXM];
    for (int i = 0; i < N; i++) {
        for (int j = 0; j < M; j++) {
            dp[i][j] = 0;
        }
    }
    dp[0][0] = 1;
    for (int step = 0; step < t; step++) {
        int new_dp[MAXN][MAXM];
        for (int i = 0; i < N; i++) {
            for (int j = 0; j < M; j++) {
                new_dp[i][j] = 0;
            }
        }
        for (int i = 0; i < N; i++) {
            for (int j = 0; j < M; j++) {
                if (dp[i][j] == 0) continue;
                for (int x = -R1; x <= R1; x++) {
                    for (int y = -R1; y <= R1; y++) {
                        int new_i = i + x;
                        int new_j = j + y;
                        if (new_i < 0 || new_i >= N || new_j < 0 || new_j >= M) continue;
                        bool valid = true;
                        for (int k = 0; k < K; k++) {
                            if (minions[k][0] == new_i && minions[k][1] == new_j) {
                                valid = false;
                                break;
                            }
                        }
                        if (valid) {
                            new_dp[new_i][new_j] = (new_dp[new_i][new_j] + dp[i][j]) % MOD;
                        }
                    }
                }
            }
        }
        for (int i = 0; i < N; i++) {
            for (int j = 0; j < M; j++) {
                dp[i][j] = new_dp[i][j];
            }
        }
    }
    int ans = 0;
    for (int i = 0; i < N; i++) {
        for (int j = 0; j < M; j++) {
            ans = (ans + dp[i][j]) % MOD;
        }
    }
    printf("%d\n", ans);
    return 0;
}

